function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  // If rawTags is an array, flatten comma-separated strings inside it
  let list = [];
  if (Array.isArray(rawTags)) {
    rawTags.forEach((item) => {
      if (typeof item === 'string') {
        list = list.concat(item.split(','));
      }
    });
  } else {
    list = String(rawTags).split(',');
  }
  return list
    .map((tag) => String(tag || '').trim().toLowerCase())
    .filter((tag) => tag);
}

/**
 * Check whether the problem contains at least one of the requested tags.
 * @param {Object} problem
 * @param {Array<string>} tags
 * @returns {boolean}
 */
function problemHasAnyTag(problem, tags) {
  if (!tags || tags.length === 0) {
    return true;
  }
  if (!problem.metadata || !Array.isArray(problem.metadata.appliedTags)) {
    return false;
  }
  const problemTags = problem.metadata.appliedTags.map((t) => t.toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

